import{_ as t,c as d,o as e,V as o}from"./chunks/framework.1sOznGPE.js";const u=JSON.parse('{"title":"常用的 npm 命令","description":"","frontmatter":{},"headers":[],"relativePath":"guide/node/npm/npm命令.md","filePath":"guide/node/npm/npm命令.md","lastUpdated":null}'),n={name:"guide/node/npm/npm命令.md"},c=o('<h1 id="常用的-npm-命令" tabindex="-1">常用的 npm 命令 <a class="header-anchor" href="#常用的-npm-命令" aria-label="Permalink to &quot;常用的 npm 命令&quot;">​</a></h1><blockquote><p>npm install 安装模块的时候一般是扁平化安装的，但是有时候出现嵌套的情况是因为版本不同 A 依赖 C1.0, B 依赖 C1.0, D 依赖 C2.0, 此时C 1.0就会被放到A B的node_moduels, C2.0 会被放入D模块下面的node_moduels</p></blockquote><table><thead><tr><th>命令</th><th>描述</th></tr></thead><tbody><tr><td><code>npm init</code></td><td>初始化一个新的 npm 项目，创建 package.json 文件</td></tr><tr><td><code>npm install</code></td><td>安装一个包或一组包，并且会在当前目录存放一个node_modules</td></tr><tr><td><code>npm install &lt;package-name&gt;</code></td><td>安装指定的包，并将其添加到 package.json 文件中的 <code>dependencies</code> 依赖列表中</td></tr><tr><td><code>npm install &lt;package-name&gt; --save</code></td><td>安装指定的包，并将其添加到 package.json 文件中的 <code>dependencies</code> 依赖列表中，等同于 <code>npm i -S xxx</code> 或 <code>npm i xxx</code></td></tr><tr><td><code>npm install &lt;package-name&gt; --save-dev</code></td><td>安装指定的包，并将其添加到 package.json 文件中的 <code>devDependencies</code> 开发依赖列表中，等同于 <code>npm i -D xxx</code></td></tr><tr><td><code>npm install -g &lt;package-name&gt;</code></td><td>全局安装指定的包</td></tr><tr><td><code>npm update &lt;package-name&gt;</code></td><td>更新指定的包</td></tr><tr><td><code>npm uninstall &lt;package-name&gt;</code></td><td>卸载指定的包</td></tr><tr><td><code>npm run &lt;script-name&gt;</code></td><td>执行 package.json 文件中定义的脚本命令</td></tr><tr><td><code>npm search &lt;keyword&gt;</code></td><td>搜索 npm 库中包含指定关键字的包</td></tr><tr><td><code>npm info &lt;package-name&gt;</code></td><td>查看指定包的详细信息</td></tr><tr><td><code>npm list</code></td><td>列出当前项目中安装的所有包</td></tr><tr><td><code>npm outdated</code></td><td>列出当前项目中需要更新的包</td></tr><tr><td><code>npm audit</code></td><td>检查当前项目中的依赖项是否存在安全漏洞</td></tr><tr><td><code>npm publish</code></td><td>发布自己开发的包到 npm 库中</td></tr><tr><td><code>npm login</code></td><td>登录到 npm 账户</td></tr><tr><td><code>npm logout</code></td><td>注销当前 npm 账户</td></tr><tr><td><code>npm link</code></td><td>将本地模块链接到全局的 <code>node_modules</code> 目录下</td></tr><tr><td><strong><code>npm config list</code></strong></td><td>用于列出所有的 npm 配置信息。执行该命令可以查看当前系统和用户级别的所有 npm 配置信息，以及当前项目的配置信息（如果在项目目录下执行该命令）</td></tr><tr><td><code>npm get registry</code></td><td>用于获取当前 npm 配置中的 registry 配置项的值。registry 配置项用于指定 npm 包的下载地址，如果未指定，则默认使用 npm 官方的包注册表地址</td></tr><tr><td><code>npm config set registry &lt;registry-url&gt;</code></td><td>将 registry 配置项的值修改为指定的 <code>&lt;registry-url&gt;</code> 地址</td></tr></tbody></table>',3),r=[c];function a(p,m,s,l,i,g){return e(),d("div",null,r)}const h=t(n,[["render",a]]);export{u as __pageData,h as default};
